function home() {
  return '<h1>Home Page Contents</h1>';
}
function about() {
  return '<h1>About Page Contents</h1>';
}
function contact() {
  return '<h1>Contact Page Contents</h1>';
}
function defaultPage() {
  return '<h1>404 Page Not Found</h1>';
}
const refRoot = document.getElementById('root');
function LoadUI(t) {
  let e = '';
  switch (t) {
    case 'home':
      e = home();
      break;
    case 'about':
      e = about();
      break;
    case 'contact':
      e = contact();
      break;
    default:
      e = defaultPage();
  }
  refRoot.innerHTML = e;
}
LoadUI('home');
